import urllib.request, urllib.error
base='http://localhost:5000'
words='''admin secret debug console flag flags flag.txt flag.php robots.txt sitemap.txt api login register upload uploads download file source src src.zip readme README readme.txt .git .env config cfg settings settings.py app.py server.py index page pages page1 page2 xss xss1 xss2 xss31 umbrella dalgona level challenge challenges solve hint hints help asset assets static/js static/css static/img static/assets static/flags'''.split()
# Build candidate paths
cands=set()
for w in words:
    cands.add('/'+w)
    cands.add('/'+w+'/')
# also try common param patterns
for p in list(cands):
    if p.endswith('/'):
        cands.add(p+'index')
        cands.add(p+'index.html')

found=[]
for p in sorted(cands):
    try:
        with urllib.request.urlopen(base+p) as r:
            found.append((p, r.getcode(), r.headers.get('Content-Type',''), r.headers.get('Content-Length','')))
    except urllib.error.HTTPError as e:
        if e.code in (401,403):
            found.append((p, e.code, 'restricted', ''))
    except Exception:
        pass

for item in found:
    print(*item)
